const call = $('Loop Over Calls').item.json;
const utterances = call.utterances || [];
const rules = $('Fetch Rules').all().map(r => r.json);

const flags = [];

for (const rule of rules) {
  if (!rule.active) continue;

  if (rule.rule_type === 'compliance_required') {
    const speakerUtterances = rule.speaker
      ? utterances.filter(u => u.speaker === rule.speaker)
      : utterances;
    const found = speakerUtterances.some(u =>
      rule.keywords.some(kw => (u.text || '').toLowerCase().includes(kw.toLowerCase()))
    );
    if (!found) {
      flags.push({
        flag_name: rule.flag_name,
        rule_type: rule.rule_type,
        severity: rule.severity,
        matched_keyword: null,
        speaker: rule.speaker,
        utterance_index: null
      });
    }
    continue;
  }

  for (let i = 0; i < utterances.length; i++) {
    const u = utterances[i];
    if (rule.speaker && u.speaker !== rule.speaker) continue;
    const text = (u.text || '').toLowerCase();
    for (const kw of rule.keywords) {
      if (text.includes(kw.toLowerCase())) {
        flags.push({
          flag_name: rule.flag_name,
          rule_type: rule.rule_type,
          severity: rule.severity,
          matched_keyword: kw,
          speaker: u.speaker,
          utterance_index: i
        });
        break;
      }
    }
  }
}

const hasComplianceIssue = flags.some(f => f.rule_type.startsWith('compliance'));
const analyzedAt = new Date().toISOString();

// Format transcript for Ollama: "Agent: ...", "Lead: ..."
const transcript_formatted = utterances
  .map(u => (u.speaker === 'A' ? 'Agent' : 'Lead') + ': ' + (u.text || ''))
  .join('\n');

return [{
  json: {
    call_key: call.call_key,
    flags,
    has_compliance_issue: hasComplianceIssue,
    agent_sentiment_ok: !flags.some(f => f.rule_type === 'sentiment_agent'),
    analyzed_at: analyzedAt,
    transcript_formatted
  }
}];

const analysis = $('Analyze Call').item.json;
const raw = ($json.message?.content || $json.response || $json.text || '').trim().toLowerCase().replace(/[^a-z_]/g, '');

const validOutcomes = ['not_interested','callback_requested','strong_interest','appointment_set','no_signal'];
const outcome = validOutcomes.includes(raw) ? raw : 'no_signal';

const patch_body = JSON.stringify({
  analysis_flags: analysis.flags,
  analysis_summary: {
    compliance_pass: !analysis.has_compliance_issue,
    agent_sentiment_ok: analysis.agent_sentiment_ok,
    outcome,
    flag_count: analysis.flags.length
  },
  analyzed_at: analysis.analyzed_at
});

return [{ json: { call_key: analysis.call_key, patch_body } }];
